import os
import requests
from mcp import tool as mcp

@mcp.tool()
def search_for_issues_using_jql_enhanced_search_get(jql_query, nextPageToken, page_size, include_fields, expand, properties, fieldsByKeys, failFast, reconcileIssues):
    params = {
        "jql_query": jql_query,
        "nextPageToken": nextPageToken,
        "page_size": page_size,
        "include_fields": include_fields,
        "expand": expand,
        "properties": properties,
        "fieldsByKeys": fieldsByKeys,
        "failFast": failFast,
        "reconcileIssues": reconcileIssues,
    }
    base_url = os.environ["JIRA_BASE_URL"].rstrip("/")
    headers = {"Accept": "application/json"}
    if os.environ.get("JIRA_API_TOKEN") and os.environ.get("JIRA_EMAIL"):
        auth = (os.environ["JIRA_EMAIL"], os.environ["JIRA_API_TOKEN"])
    else:
        auth = None
        if os.environ.get("JIRA_BEARER_TOKEN"):
            headers["Authorization"] = f"Bearer {os.environ['JIRA_BEARER_TOKEN']}"
    r = requests.get(f"{base_url}/rest/api/3/search/jql_query", params=params, headers=headers, auth=auth)
    r.raise_for_status()
    return r.json()
